module RefModule(  
    input clk,  
    input signal_in,  
    output reg signal_out  
);  
    reg signal_in_d; // Delayed version of the input signal  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        signal_in_d <= signal_in;  
        signal_out <= (signal_in && !signal_in_d);  
    end  
endmodule
